import { router } from 'expo-router';

export function handleDeepLink(url: string) {
  try {
    const parsed = new URL(url);
    const path = parsed.pathname;

    if (path.startsWith('/scan/')) {
      const token = path.replace('/scan/', '');
      router.push({ pathname: '/(tabs)/scan', params: { token } });
    } else if (path.startsWith('/offer/')) {
      const token = path.replace('/offer/', '');
      router.push(`/offer/${token}`);
    } else if (path.includes('/customer/dashboard')) {
      router.replace('/(tabs)/');
    } else if (path.includes('/customer/cards/')) {
      const parts = path.split('/');
      const cardId = parts[parts.length - 1];
      router.push(`/(tabs)/cards/${cardId}`);
    } else if (path.includes('/customer/cards')) {
      router.push('/(tabs)/cards/');
    } else {
      router.replace('/(tabs)/');
    }
  } catch {
    // Invalid URL, ignore
  }
}

export function parseQRUrl(url: string): { type: 'scan' | 'offer' | 'unknown'; token: string | null } {
  try {
    const appUrl = process.env.EXPO_PUBLIC_APP_URL || '';
    const parsed = new URL(url);
    const path = parsed.pathname;

    if (path.startsWith('/scan/')) {
      return { type: 'scan', token: path.replace('/scan/', '') };
    }
    if (path.startsWith('/offer/')) {
      return { type: 'offer', token: path.replace('/offer/', '') };
    }
    return { type: 'unknown', token: null };
  } catch {
    return { type: 'unknown', token: null };
  }
}
