import React, { createContext, useContext, useEffect, useState, type ReactNode } from 'react';
import { Platform } from 'react-native';
import { useAuth } from './AuthContext';
import { initOneSignal, getPlayerId } from '../lib/onesignal';
import { supabase } from '../lib/supabase';

interface PushContextValue {
  pushEnabled: boolean;
  playerId: string | null;
}

const PushContext = createContext<PushContextValue>({
  pushEnabled: false,
  playerId: null,
});

export function PushProvider({ children }: { children: ReactNode }) {
  const { profile } = useAuth();
  const [playerId, setPlayerId] = useState<string | null>(null);
  const [pushEnabled, setPushEnabled] = useState(false);

  useEffect(() => {
    initOneSignal();
  }, []);

  useEffect(() => {
    if (!profile) return;

    const registerPlayer = async () => {
      const id = await getPlayerId();
      if (!id) return;

      setPlayerId(id);
      setPushEnabled(true);

      // Register in onesignal_subscriptions table
      const deviceType = Platform.OS === 'ios' ? 'ios' : 'android';

      await supabase.from('onesignal_subscriptions').upsert(
        {
          profile_id: profile.id,
          player_id: id,
          device_type: deviceType,
          is_active: true,
        },
        { onConflict: 'profile_id,player_id' }
      );
    };

    // Small delay to let OneSignal initialize
    const timer = setTimeout(registerPlayer, 2000);
    return () => clearTimeout(timer);
  }, [profile]);

  return (
    <PushContext.Provider value={{ pushEnabled, playerId }}>
      {children}
    </PushContext.Provider>
  );
}

export function usePush() {
  return useContext(PushContext);
}
