import { useState, useCallback, useRef } from 'react';
import { Alert } from 'react-native';
import * as Haptics from 'expo-haptics';
import { supabase } from '../lib/supabase';
import { parseQRUrl } from '../lib/deep-linking';
import type { CustomerScanSuccessData } from '@astrolab/shared';

interface ScanResult {
  success: boolean;
  data?: CustomerScanSuccessData;
  error?: { code: string; message: string };
}

interface UseQRScannerResult {
  isProcessing: boolean;
  scanResult: ScanResult | null;
  error: string | null;
  flash: boolean;
  toggleFlash: () => void;
  handleBarCodeScanned: (data: string) => Promise<void>;
  resetScan: () => void;
}

export function useQRScanner(): UseQRScannerResult {
  const [isProcessing, setIsProcessing] = useState(false);
  const [scanResult, setScanResult] = useState<ScanResult | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [flash, setFlash] = useState(false);
  const cooldownRef = useRef(false);

  const toggleFlash = () => setFlash((f) => !f);

  const resetScan = useCallback(() => {
    setScanResult(null);
    setError(null);
    setIsProcessing(false);
    cooldownRef.current = false;
  }, []);

  const handleBarCodeScanned = useCallback(async (rawData: string) => {
    if (cooldownRef.current || isProcessing) return;

    cooldownRef.current = true;
    setIsProcessing(true);
    setError(null);

    // Haptic feedback
    await Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Medium);

    const parsed = parseQRUrl(rawData);

    if (parsed.type === 'scan' && parsed.token) {
      try {
        const { data: { session } } = await supabase.auth.getSession();

        const res = await fetch(
          `${process.env.EXPO_PUBLIC_SUPABASE_URL}/functions/v1/process-customer-scan`,
          {
            method: 'POST',
            headers: {
              'Content-Type': 'application/json',
              Authorization: `Bearer ${session?.access_token}`,
            },
            body: JSON.stringify({ token: parsed.token }),
          }
        );

        const result = await res.json();

        if (result.success) {
          await Haptics.notificationAsync(Haptics.NotificationFeedbackType.Success);
          setScanResult({ success: true, data: result.data });
        } else {
          await Haptics.notificationAsync(Haptics.NotificationFeedbackType.Error);
          setScanResult({ success: false, error: result.error });
        }
      } catch (err) {
        await Haptics.notificationAsync(Haptics.NotificationFeedbackType.Error);
        setScanResult({
          success: false,
          error: { code: 'NETWORK_ERROR', message: 'Erreur de connexion' },
        });
      }
    } else if (parsed.type === 'offer' && parsed.token) {
      // Offer QR - navigate to offer page
      setScanResult({
        success: true,
        data: { offerToken: parsed.token } as unknown as CustomerScanSuccessData,
      });
    } else {
      await Haptics.notificationAsync(Haptics.NotificationFeedbackType.Error);
      setError('QR code non reconnu');
      setScanResult({
        success: false,
        error: { code: 'UNKNOWN_QR', message: 'Ce QR code n\'est pas un QR AstroLab' },
      });
    }

    setIsProcessing(false);

    // Reset cooldown after 3 seconds
    setTimeout(() => {
      cooldownRef.current = false;
    }, 3000);
  }, [isProcessing]);

  return {
    isProcessing,
    scanResult,
    error,
    flash,
    toggleFlash,
    handleBarCodeScanned,
    resetScan,
  };
}
```

