import { useEffect, useRef } from 'react';
import * as Brightness from 'expo-brightness';

export function useBrightness(shouldMaximize: boolean) {
  const previousBrightness = useRef<number | null>(null);

  useEffect(() => {
    if (!shouldMaximize) return;

    let mounted = true;

    const maximize = async () => {
      try {
        const current = await Brightness.getBrightnessAsync();
        if (mounted) {
          previousBrightness.current = current;
          await Brightness.setBrightnessAsync(1);
        }
      } catch {
        // Permission denied or not available
      }
    };

    maximize();

    return () => {
      mounted = false;
      if (previousBrightness.current !== null) {
        Brightness.setBrightnessAsync(previousBrightness.current).catch(() => {});
      }
    };
  }, [shouldMaximize]);
}
