  signOut: () => Promise<void>;
  resetPassword: (email: string) => Promise<{ error: string | null }>;
  isAuthenticated: boolean;
}

const AuthContext = createContext<AuthContextValue | null>(null);

export function AuthProvider({ children }: { children: ReactNode }) {
  const [user, setUser] = useState<User | null>(null);
  const [profile, setProfile] = useState<Profile | null>(null);
  const [session, setSession] = useState<Session | null>(null);
  const [loading, setLoading] = useState(true);

  const fetchProfile = useCallback(async (userId: string) => {
    const { data } = await supabase
      .from('profiles')
      .select('*')
      .eq('id', userId)
      .single();
    setProfile(data as Profile | null);
    if (data) {
      setExternalUserId(data.id);
    }
  }, []);

  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session: s } }) => {
      setSession(s);
      setUser(s?.user ?? null);
      if (s?.user) {
        fetchProfile(s.user.id).finally(() => setLoading(false));
      } else {
        setLoading(false);
      }
    });

    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, s) => {
      setSession(s);
      setUser(s?.user ?? null);
      if (s?.user) {
        fetchProfile(s.user.id);
      } else {
        setProfile(null);
      }
    });

    return () => subscription.unsubscribe();
  }, [fetchProfile]);

  const signIn = async (email: string, password: string) => {
    const { error } = await supabase.auth.signInWithPassword({ email, password });
    return { error: error?.message ?? null };
  };

  const signUp = async (email: string, password: string, fullName: string) => {
    const { error } = await supabase.auth.signUp({
      email,
      password,
      options: {
        data: { role: 'customer', full_name: fullName },
      },
    });
    return { error: error?.message ?? null };
  };

  const signOut = async () => {
    removeExternalUserId();
    await supabase.auth.signOut();
    setUser(null);
    setProfile(null);
    setSession(null);
  };

  const resetPassword = async (email: string) => {
    const { error } = await supabase.auth.resetPasswordForEmail(email, {
      redirectTo: 'astrolab://reset-password',
    });
    return { error: error?.message ?? null };
  };

  return (
    <AuthContext.Provider
      value={{
        user,
        profile,
        session,
        loading,
        signIn,
        signUp,
        signOut,
        resetPassword,
        isAuthenticated: !!user && !!profile,
      }}
    >
      {children}
    </AuthContext.Provider>
  );
}

export function useAuth() {
  const ctx = useContext(AuthContext);
  if (!ctx) {
    throw new Error('useAuth must be used within AuthProvider');
  }
  return ctx;
}

import React, { createContext, useContext, useEffect, useState, type ReactNode } from 'react';
import { Platform } from 'react-native';
import { useAuth } from './AuthContext';
import { initOneSignal, getPlayerId } from '../lib/onesignal';
import { supabase } from '../lib/supabase';

interface PushContextValue {
  pushEnabled: boolean;
  playerId: string | null;
}

const PushContext = createContext<PushContextValue>({
  pushEnabled: false,
  playerId: null,
});

export function PushProvider({ children }: { children: ReactNode }) {
  const { profile } = useAuth();
  const [playerId, setPlayerId] = useState<string | null>(null);
  const [pushEnabled, setPushEnabled] = useState(false);

  useEffect(() => {
    initOneSignal();
  }, []);

  useEffect(() => {
    if (!profile) return;

    const registerPlayer = async () => {
      const id = await getPlayerId();
      if (!id) return;

      setPlayerId(id);
      setPushEnabled(true);

      // Register in onesignal_subscriptions table
      const deviceType = Platform.OS === 'ios' ? 'ios' : 'android';

      await supabase.from('onesignal_subscriptions').upsert(
        {
          profile_id: profile.id,
          player_id: id,
          device_type: deviceType,
          is_active: true,
        },
        { onConflict: 'profile_id,player_id' }
      );
    };

    // Small delay to let OneSignal initialize
    const timer = setTimeout(registerPlayer, 2000);
    return () => clearTimeout(timer);
  }, [profile]);

  return (
    <PushContext.Provider value={{ pushEnabled, playerId }}>
      {children}
    </PushContext.Provider>
  );
}

export function usePush() {
  return useContext(PushContext);
}

import { useState, useEffect, useCallback } from 'react';
import { getCached, setCache } from '../lib/cache';

interface UseCachedQueryResult<T> {
  data: T | null;
  loading: boolean;
  error: string | null;
  isFromCache: boolean;
  refresh: () => Promise<void>;
}

export function useCachedQuery<T>(
  cacheKey: string,
  fetcher: () => Promise<T>,
  deps: unknown[] = []
): UseCachedQueryResult<T> {
  const [data, setData] = useState<T | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [isFromCache, setIsFromCache] = useState(false);

  const fetchData = useCallback(async () => {
    setLoading(true);
    setError(null);

    // Try cache first
    const cached = await getCached<T>(cacheKey);
    if (cached) {
      setData(cached);
      setIsFromCache(true);
      setLoading(false);
    }

    // Then fetch fresh data
    try {
      const fresh = await fetcher();
      setData(fresh);
      setIsFromCache(false);
      await setCache(cacheKey, fresh);
    } catch (err) {
      if (!cached) {
        setError(err instanceof Error ? err.message : 'Erreur inconnue');
      }
      // If we have cache, keep showing it
    } finally {
      setLoading(false);
    }
  }, [cacheKey, ...deps]);

  useEffect(() => {
    fetchData();
  }, [fetchData]);

  return { data, loading, error, isFromCache, refresh: fetchData };
}

import { useState, useCallback, useRef } from 'react';
import { Alert } from 'react-native';
import * as Haptics from 'expo-haptics';
import { supabase } from '../lib/supabase';
import { parseQRUrl } from '../lib/deep-linking';
import type { CustomerScanSuccessData } from '@astrolab/shared';

interface ScanResult {
  success: boolean;
  data?: CustomerScanSuccessData;
  error?: { code: string; message: string };
}

interface UseQRScannerResult {
  isProcessing: boolean;
  scanResult: ScanResult | null;
  error: string | null;
  flash: boolean;
  toggleFlash: () => void;
  handleBarCodeScanned: (data: string) => Promise<void>;
  resetScan: () => void;
}

export function useQRScanner(): UseQRScannerResult {
  const [isProcessing, setIsProcessing] = useState(false);
  const [scanResult, setScanResult] = useState<ScanResult | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [flash, setFlash] = useState(false);
  const cooldownRef = useRef(false);

  const toggleFlash = () => setFlash((f) => !f);

  const resetScan = useCallback(() => {
    setScanResult(null);
    setError(null);
    setIsProcessing(false);
    cooldownRef.current = false;
  }, []);

  const handleBarCodeScanned = useCallback(async (rawData: string) => {
    if (cooldownRef.current || isProcessing) return;

    cooldownRef.current = true;
    setIsProcessing(true);
    setError(null);

    // Haptic feedback
    await Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Medium);

    const parsed = parseQRUrl(rawData);

    if (parsed.type === 'scan' && parsed.token) {
      try {
        const { data: { session } } = await supabase.auth.getSession();

        const res = await fetch(
          `${process.env.EXPO_PUBLIC_SUPABASE_URL}/functions/v1/process-customer-scan`,
          {
            method: 'POST',
            headers: {
              'Content-Type': 'application/json',
              Authorization: `Bearer ${session?.access_token}`,
            },
            body: JSON.stringify({ token: parsed.token }),
          }
        );

        const result = await res.json();

        if (result.success) {
          await Haptics.notificationAsync(Haptics.NotificationFeedbackType.Success);
          setScanResult({ success: true, data: result.data });
        } else {
          await Haptics.notificationAsync(Haptics.NotificationFeedbackType.Error);
          setScanResult({ success: false, error: result.error });
        }
      } catch (err) {
        await Haptics.notificationAsync(Haptics.NotificationFeedbackType.Error);
        setScanResult({
          success: false,
          error: { code: 'NETWORK_ERROR', message: 'Erreur de connexion' },
        });
      }
    } else if (parsed.type === 'offer' && parsed.token) {
      // Offer QR - navigate to offer page
      setScanResult({
        success: true,
        data: { offerToken: parsed.token } as unknown as CustomerScanSuccessData,
      });
    } else {
      await Haptics.notificationAsync(Haptics.NotificationFeedbackType.Error);
      setError('QR code non reconnu');
      setScanResult({
        success: false,
        error: { code: 'UNKNOWN_QR', message: 'Ce QR code n\'est pas un QR AstroLab' },
      });
    }

    setIsProcessing(false);

    // Reset cooldown after 3 seconds
    setTimeout(() => {
      cooldownRef.current = false;
    }, 3000);
  }, [isProcessing]);

  return {
    isProcessing,
    scanResult,
    error,
    flash,
    toggleFlash,
    handleBarCodeScanned,
    resetScan,
  };
}

import { useEffect, useRef } from 'react';
import * as Brightness from 'expo-brightness';

export function useBrightness(shouldMaximize: boolean) {
  const previousBrightness = useRef<number | null>(null);

  useEffect(() => {
    if (!shouldMaximize) return;

    let mounted = true;

    const maximize = async () => {
      try {
        const current = await Brightness.getBrightnessAsync();
        if (mounted) {
          previousBrightness.current = current;
          await Brightness.setBrightnessAsync(1);
        }
      } catch {
        // Permission denied or not available
      }
    };

    maximize();

    return () => {
      mounted = false;
      if (previousBrightness.current !== null) {
        Brightness.setBrightnessAsync(previousBrightness.current).catch(() => {});
      }
    };
  }, [shouldMaximize]);
}
